+impl fmt::Display for ParseEventMaterializationError {
+    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
+        if let Some(sequence) = self.sequence {
+            write!(
+                f,
+                "{} (sequence={}): {}",
+                self.code.as_str(),
+                sequence,
+                self.message
+            )
+        } else {
+            write!(f, "{}: {}", self.code.as_str(), self.message)
+        }
+    }
+}
